package com.samudhra.certificates.config;
import com.samudhra.certificates.repository.UserRepository; import com.samudhra.certificates.security.JwtAuthenticationFilter; import org.springframework.context.annotation.*; import org.springframework.security.config.annotation.web.builders.HttpSecurity; import org.springframework.security.config.http.SessionCreationPolicy; import org.springframework.security.core.userdetails.*; import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.security.web.SecurityFilterChain; import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
@Configuration public class SecurityConfig {
 @Bean PasswordEncoder passwordEncoder(){return new BCryptPasswordEncoder();}
 @Bean UserDetailsService users(UserRepository repository, com.samudhra.certificates.repository.AdminRepository adminRepository){return email->adminRepository.findByEmail(email).map(admin->User.withUsername(admin.getEmail()).password(admin.getPassword()).roles("ADMIN").build()).or(()->repository.findByEmail(email).map(u->User.withUsername(u.getEmail()).password(u.getPasswordHash()).roles(u.getRole()).build())).orElseThrow(()->new UsernameNotFoundException("User not found: "+email));}
 @Bean SecurityFilterChain security(HttpSecurity http,JwtAuthenticationFilter jwt)throws Exception{return http.csrf(c->c.disable()).cors(c->{}).sessionManagement(s->s.sessionCreationPolicy(SessionCreationPolicy.STATELESS)).authorizeHttpRequests(a->a.requestMatchers("/api/auth/**","/api/certificates/verify/**","/uploads/**","/","/*.html","/css/**","/js/**","/assets/**").permitAll().anyRequest().authenticated()).addFilterBefore(jwt,UsernamePasswordAuthenticationFilter.class).build();}
}
